+    unused,
+    begin,
+    end,
+    left,
+    right,
+    word_break,
+    not_word_break,
+    alt,
+    optional,
+    star,
+    plus,
+    lazy_optional,
+    lazy_star,
+    lazy_plus,
+    eager_optional,
+    eager_star,
+    eager_plus,
+    some,
+    up_to,
+    eager_up_to,
+    dot,
+    char,
+    class,
+    not_class,
+    high_class,
+    not_high_class,
+    digit,
+    not_digit,
+    alpha,
+    not_alpha,
+    whitespace,
+    not_whitespace, // #26, can add five before bumping to u6
+};
