+pub const RegOp = union(RegexType) {
+    unused: void,
+    begin: void,
+    end: void,
+    left: void, // TODO add offset u8
+    right: void, // TODO add head-match offset
+    word_break: void,
+    not_word_break: void,
+    alt: void, // TODO add offset u8
+    optional: void,
+    star: void,
+    plus: void,
+    lazy_optional: void,
+    lazy_star: void,
+    lazy_plus: void,
+    eager_optional: void,
+    eager_star: void,
+    eager_plus: void,
+    some: u8,
+    up_to: u8,
+    eager_up_to: u8,
+    dot: void,
+    char: u8, // character byte
+    class: u8, // offset into class array (ASCII)
+    not_class: u8,
+    high_class: u8, // offset into class array (high bytes)
+    not_high_class: u8,
+    digit: void,
+    not_digit: void,
+    alpha: void,
+    not_alpha: void,
+    whitespace: void,
+    not_whitespace: void,
