+                .begin,
+                .plus,
+                .lazy_plus,
+                .eager_plus,
+                .dot,
+                .class,
+                .not_class,
+                .high_class,
+                .not_high_class,
+                .digit,
+                .not_digit,
+                .alpha,
+                .not_alpha,
+                .whitespace,
+                .not_whitespace,
+                .char,
