+fn matchOptional(patt: []const RegOp, sets: []const CharSet, haystack: []const u8, i_in: usize) ?OpMatch {
+    const this_patt = thisPattern(patt);
+    const maybe_m = matchPattern(this_patt, sets, haystack, i_in);
