+    std.debug.print("[", .{});
+    while (j < patt.len and patt[j] != .unused) : (j += 1) {
+        switch (patt[j]) {
+            .char,
+            => |op| {
+                switch (op) {
+                    0...0x3f => {
+                        std.debug.print("char 0x{x:0>2}", .{op});
