+                    0x40...0x7e => {
+                        std.debug.print("char '{u}'", .{op});
+                    },
+                    0x7f...0xff => {
+                        std.debug.print("char 0x{x:0>2}", .{op});
+                    },
+                }
+            },
+            .some,
+            .up_to,
+            .eager_up_to,
+            => |op| {
+                std.debug.print("{s} {d}", .{ @tagName(patt[j]), op });
+            },
+            .class,
+            .not_class,
+            => |op| {
+                if (set_max) |max| {
+                    set_max = @max(max, op);
+                } else {
+                    set_max = op;
+                }
+                std.debug.print("{s} {d}", .{ @tagName(patt[j]), op });
+            },
+            else => {
+                std.debug.print("{s}", .{@tagName(patt[j])});
+            },
+        }
+        if (j + 1 < patt.len and patt[j + 1] != .unused) {
+            std.debug.print(", ", .{});
+        }
+    }
+    std.debug.print("]\n", .{});
+    return set_max;
