+                self.advance();
+                return Expr{ .any = {} };
+            },
+            '^' => {
+                self.advance();
+                return Expr{ .start = {} };
+            },
+            '$' => {
+                self.advance();
+                return Expr{ .end = {} };
+            },
+            '(' => {
+                return try self.parseGroup();
+            },
+            '[' => {
+                return try self.parseCharClass();
+            },
+            '\\' => {
+                return try self.parseEscape();
+            },
+            // Metacharacters that shouldn't appear here
+            '*', '+', '?', '{', '}', '|', ')' => {
+                return error.UnexpectedEOF; // TODO: Better error
+            },
+            else => {
+                self.advance();
+                return Expr{ .char = c };
+            },
+        }
+    }
