+    pub fn exactly(n: usize) RepeatBounds {
+        return .{ .min = n, .max = n };
+    }
+
+    pub fn atLeast(n: usize) RepeatBounds {
+        return .{ .min = n, .max = null };
+    }
+
+    pub fn between(min: usize, max: usize) RepeatBounds {
+        return .{ .min = min, .max = max };
