+pub fn benchmark(
+    allocator: std.mem.Allocator,
+    name: []const u8,
+    pattern: []const u8,
+    input: []const u8,
+    iterations: usize,
+) !void {
+    var regex = try Regex.compile(allocator, pattern);
+    defer regex.deinit();
+
+    const start = std.time.nanoTimestamp();
+
+    for (0..iterations) |_| {
+        const result = try regex.find(input);
+        if (result) |match| {
+            var mut_match = match;
