+    try std.testing.expectEqual(ComplexityAnalyzer.ComplexityLevel.low, simple.getLevel());
+
+    const complex = ComplexityAnalyzer.analyze("(((a+)+)+)|(((b*)*)*)|c{1,100}");
+    try std.testing.expect(complex.complexity_score > 20);
+}

