+/// Check if a codepoint is whitespace
+pub fn isWhitespace(cp: Codepoint) bool {
+    const cat = getGeneralCategory(cp);
+    return cat == .Zs or cat == .Zl or cat == .Zp or
+        cp == '\t' or cp == '\n' or cp == '\r' or cp == 0x0B or cp == 0x0C;
